const hamburger=document.getElementById('hamburger');const navLinks=document.getElementById('nav-links');hamburger.addEventListener('click',function(){navLinks.classList.toggle('active');const expanded=navLinks.classList.contains('active');hamburger.setAttribute('aria-expanded',expanded);});hamburger.addEventListener('keydown',function(e){if(e.key==='Enter'||e.key===' '){navLinks.classList.toggle('active');const expanded=navLinks.classList.contains('active');hamburger.setAttribute('aria-expanded',expanded);}});